52	namespace detail {
53	
54	// Returns the maximum number of smem tiles that can be used with a given smem capacity, or overrides with manual count.
55	template<int capacity_bytes, class ElementA, class ElementB, class TileShapeMNK, int alignment = 128, int stages>
56	constexpr int
57	compute_stage_count_or_override(StageCount<stages> stage_count) {
58	  return stages;
59	}
60	
61	// Returns the maximum number of smem tiles that can be used with a given smem capacity, or overrides with manual count.
62	template<int capacity_bytes, class ElementA, class ElementB, class TileShapeMNK, int alignment = 128, int stages>
63	constexpr int
64	compute_stage_count_or_override(cute::Int<stages> stage_count) {
65	  return stages;
66	}
67	
68	// Returns the maximum number of smem tiles that can be used with a given smem capacity, or overrides with manual count.
69	template<int capacity_bytes_, class ElementA, class ElementB, class TileShapeMNK, int alignment = 128, int carveout_bytes_>
70	constexpr int
71	compute_stage_count_or_override(StageCountAutoCarveout<carveout_bytes_> stage_count) {
72	  constexpr auto mainloop_pipeline_bytes = sizeof(typename cutlass::PipelineTmaAsync<1>::SharedStorage);
73	  constexpr auto a_bits = cute::sizeof_bits_v<ElementA>;
74	  constexpr auto b_bits = cute::sizeof_bits_v<ElementB>;
75	  constexpr int stage_bytes_ =
76	    cutlass::bits_to_bytes(a_bits * size<0>(TileShapeMNK{}) * size<2>(TileShapeMNK{})) +
77	    cutlass::bits_to_bytes(b_bits * size<1>(TileShapeMNK{}) * size<2>(TileShapeMNK{}));
78	
79	  constexpr int stage_bytes = cutlass::round_up(stage_bytes_, alignment) +
80	    static_cast<int>(mainloop_pipeline_bytes);
81	  constexpr int carveout_bytes = cutlass::round_up(carveout_bytes_, alignment);
82	  constexpr int capacity_bytes = capacity_bytes_ / alignment * alignment;
83	
84	  return (capacity_bytes - carveout_bytes) / stage_bytes;
85	}
86	
87	// Returns the maximum number of smem tiles that can be used with a given smem capacity in gemm of blockwise/groupwise scale.
88	template<int capacity_bytes_, class ElementA, class ElementB, class ElementBlockScale, class TileShapeMNK, int ScaleMsPerTile, int ScaleNsPerTile, int alignment = 128, int carveout_bytes_>
89	constexpr int
90	compute_stage_count_with_blockwise_scale(StageCountAutoCarveout<carveout_bytes_> stage_count) {
91	  constexpr auto mainloop_pipeline_bytes = sizeof(typename cutlass::PipelineTmaAsync<1>::SharedStorage);
92	  constexpr auto a_bits = cute::sizeof_bits_v<ElementA>;
93	  constexpr auto b_bits = cute::sizeof_bits_v<ElementB>;
94	  constexpr auto scale_bits = cute::sizeof_bits_v<ElementBlockScale>;
95	  constexpr int stage_bytes_ =
96	    cutlass::bits_to_bytes(a_bits * size<0>(TileShapeMNK{}) * size<2>(TileShapeMNK{})) +
97	    cutlass::bits_to_bytes(b_bits * size<1>(TileShapeMNK{}) * size<2>(TileShapeMNK{})) +
98	    cutlass::bits_to_bytes(scale_bits * ScaleMsPerTile) + // scale of tensor A
99	    cutlass::bits_to_bytes(scale_bits * ScaleNsPerTile);  // scale of tensor B
100	
101	  constexpr int stage_bytes = cutlass::round_up(stage_bytes_, alignment) +
102	    static_cast<int>(mainloop_pipeline_bytes);
103	  constexpr int carveout_bytes = cutlass::round_up(carveout_bytes_, alignment);
104	  constexpr int capacity_bytes = capacity_bytes_ / alignment * alignment;
105	
106	  return (capacity_bytes - carveout_bytes) / stage_bytes;
107	}
