123	template <class Element>
124	constexpr int get_bits_for_possibly_void_element() {
125	  if constexpr (cute::is_same_v<Element, void>) {
126	    return 0;
127	  }
128	  else {
129	    return sizeof_bits<Element>::value;
130	  }
131	}
132	
133	// Returns the maximum number of smem tiles that can be used with a given smem capacity (with an optional scale matrix), or overrides with manual count.
134	template<int capacity_bytes_, class ElementA, class ElementB, class ElementScale, class ElementZero, class TileShapeMNK, int alignment = 128, int carveout_bytes_>
135	constexpr int
136	compute_stage_count_or_override_single_affine_transformed_input(StageCountAutoCarveout<carveout_bytes_> stage_count) {
137	
138	  // 32 bytes to account for barriers etc.
139	  constexpr auto mainloop_pipeline_bytes = sizeof(typename cutlass::PipelineTmaAsync<1>::SharedStorage);
140	  constexpr int scale_zero_k_tile = 1;
141	  constexpr auto a_bits = cute::sizeof_bits_v<ElementA>;
142	  constexpr auto b_bits = cute::sizeof_bits_v<ElementB>;
143	  constexpr auto s_bits = get_bits_for_possibly_void_element<ElementScale>();
144	  constexpr auto z_bits = get_bits_for_possibly_void_element<ElementZero>();
145	
146	  constexpr auto scale_bytes = cutlass::bits_to_bytes(s_bits * size<0>(TileShapeMNK{}) * scale_zero_k_tile);
147	  constexpr auto zero_bytes  = cutlass::bits_to_bytes(z_bits * size<0>(TileShapeMNK{}) * scale_zero_k_tile);
148	  static_assert(scale_bytes % 128 == 0, "Scale bytes must be a multiple of 128");
149	  static_assert(zero_bytes  % 128 == 0, "Zero bytes must be a multiple of 128");
150	
151	  // When scales are void, s_bits will be 0 so no smem will be allocated for scales.
152	  constexpr int stage_bytes_ =
153	    cutlass::bits_to_bytes(a_bits * size<0>(TileShapeMNK{}) * size<2>(TileShapeMNK{})) +
154	    cutlass::bits_to_bytes(b_bits * size<1>(TileShapeMNK{}) * size<2>(TileShapeMNK{})) +
155	    scale_bytes + zero_bytes;
156	
157	  constexpr int stage_bytes = cutlass::round_up(stage_bytes_, alignment) +
158	    static_cast<int>(mainloop_pipeline_bytes);
159	  constexpr int carveout_bytes = cutlass::round_up(carveout_bytes_, alignment);
160	  constexpr int capacity_bytes = capacity_bytes_ / alignment * alignment;
161	
162	  return (capacity_bytes - carveout_bytes) / stage_bytes;
163	}
