167	is_swapAB(){
168	  constexpr bool IsInputSizeTwoBytes = is_input_size_two_bytes<ElementA, ElementB>();
169	  constexpr bool IsLayoutAkBmn = cutlass::gemm::detail::is_k_major_A<LayoutA>() &&
170	                                 cutlass::gemm::detail::is_mn_major_B<LayoutB>();
171	  constexpr bool SwapAB = !IsInputSizeTwoBytes && IsLayoutAkBmn;
172	  return SwapAB;
173	}
