using LayoutTagA = cutlass::gemm::detail::StrideToLayoutTagA_t<StrideA>;
using LayoutTagB = cutlass::gemm::detail::StrideToLayoutTagB_t<StrideB>;
using LayoutTagC = cutlass::gemm::detail::StrideToLayoutTagC_t<StrideC>;
using LayoutTagD = cutlass::gemm::detail::StrideToLayoutTagC_t<StrideD>;

//
// Data members
//

/// Initialization
StrideA stride_A;
StrideB stride_B;
StrideC stride_C;
StrideD stride_D;
uint64_t seed = 0;

cutlass::DeviceAllocation<typename Gemm::ElementA> block_A;
cutlass::DeviceAllocation<typename Gemm::ElementB> block_B;
cutlass::DeviceAllocation<typename Gemm::ElementC> block_C;
cutlass::DeviceAllocation<typename Gemm::ElementD> block_D;
cutlass::DeviceAllocation<typename Gemm::ElementD> block_ref_D;

//
// Methods
//

bool verify(const ProblemShapeType& problem_size, float alpha, float beta) {
  auto [M, N, K, L] = problem_size;

  cutlass::TensorRef ref_A(block_A.get(), Gemm::LayoutA::packed({M, K}));
  cutlass::TensorRef ref_B(block_B.get(), Gemm::LayoutB::packed({K, N}));
  cutlass::TensorRef ref_C(block_C.get(), Gemm::LayoutC::packed({M, N}));
  cutlass::TensorRef ref_D(block_ref_D.get(), Gemm::LayoutD::packed({M, N}));

  cutlass::reference::device::GemmComplex(
        {M, N, K},
        ElementScalar(alpha),
        ref_A,
        cutlass::ComplexTransform::kNone,

auto blk_coord = make_coord(m_coord, n_coord, _, l_coord);

// Get pipeline iterators and increments from tensor shapes
auto k_tile_iter  = cute::make_coord_iterator(shape<3>(gA_mkl));
auto k_tile_count = size<3>(gA_mkl);

// Wait for all thread blocks in the Cluster
cluster_wait_fn();

if (warp_group_role == WarpGroupRole::Producer) {
  if (producer_warp_role == ProducerWarpRole::MainloopEpilogue) {
    // Ensure that the prefetched kernel does not touch
    // unflushed global memory prior to this instruction
    cutlass::arch::wait_on_dependent_grids();
    collective_mainloop.load(
      params.mainloop,
      mainloop_pipeline,
      mainloop_pipe_producer_state,
      load_inputs,
      blk_coord,
      k_tile_iter, k_tile_count,
      lane_idx,
      block_rank_in_cluster,
      shared_storage.tensors.mainloop
    );
    // Update starting mainloop pipeline state for the pipeline drain
    mainloop_pipe_producer_state.advance(k_tile_count);
    // Make sure mainloop consumer has been waited upon before issuing epilogue load
    collective_mainloop.load_tail(mainloop_pipeline, mainloop_pipe_producer_state);

    if (collective_epilogue.is_producer_load_needed()) {
      // Ensure warp is converged before issuing epilogue loads
      __syncwarp();
      epi_load_pipe_producer_state = collective_epilogue.load(
        epi_load_pipeline,
        epi_load_pipe_producer_state,
        problem_shape_MNKL,
        blk_shape,
        blk_coord,
        tiled_mma,
        lane_idx,
        shared_storage.tensors.epilogue
      );
      collective_epilogue.load_tail(epi_load_pipeline, epi_load_pipe_producer_state);
    }
  } 
}
else if (warp_group_role == WarpGroupRole::Consumer) {
  Tensor accumulators = partition_fragment_C(tiled_mma, take<0,2>(blk_shape));                 // (MMA,MMA_M,MMA_N)

  collective_mainloop.mma(
    mainloop_pipeline,
    mainloop_pipe_consumer_state,
    accumulators,
    k_tile_count,
    warp_group_thread_idx,
    shared_storage.tensors.mainloop,
    params.mainloop
  );

  // Make sure the math instructions are done and free buffers before entering the epilogue
  collective_mainloop.mma_tail(
    mainloop_pipeline,
    mainloop_pipe_consumer_state,
    k_tile_count
  );

  // Hint on an early release of global memory resources.
  // The timing of calling this function only influences performance,
  // not functional correctness.
  cutlass::arch::launch_dependent_grids();

  // Epilogue and write to gD
  auto [epi_load_pipe_consumer_state_next, epi_store_pipe_producer_state_next] =
  collective_epilogue.store(
    epi_load_pipeline,
    epi_load_pipe_consumer_state,
    epi_store_pipeline,
    epi_store_pipe_producer_state,
    problem_shape_MNKL,
    blk_shape,
    blk_coord,
    accumulators,
    tiled_mma,
    warp_group_thread_idx,
    shared_storage.tensors.epilogue
  );

  collective_epilogue.store_tail(
    epi_load_pipeline,
    epi_load_pipe_consumer_state_next,
    epi_store_pipeline,
    epi_store_pipe_producer_state_next
  );

